202: const InputMode = enum(u8) {
203:     // By pass Vietnamese input processing and append the character as is.
204:     literal,
205:     // Process Vietnamese input in Telex input method.
206:     telex,
207: };
208: 
209: const State = struct {
210:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
211:     // longer than 16.
212:     buffer_effective: [16]Span,
213:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
214:     // value (255), we will reset the effective buffer and this value.
215:     buffer_length: u8 = 0,
216:     // Mark the earliest position (inclusive) in buffer where we modified the span, will be used to
217:     // calculate backspaces and replacement characters.
218:     buffer_modification_index: ?u8 = null,
219:     // Mark the position (inclusive) in buffer where we will switch to literal mode (due to manually
220:     // switch, input cancellation, exceed effective buffer). This value is only used in .telex mode
221:     // and the engine is working on position on or after literal index, the engine will skip
222:     // Vietnamese input processing (we only count valid numbers, null mean no literal index).
223:     literal_index: ?u8 = null,
224:     // Determine if we will process input in the specified mode (Telex) or append the character as is.
225:     mode: InputMode = .literal,
226: 
227:     // Initialize the State on allocated memory.
228:     fn init(self: *State) void {
229:         self.* = .{
230:             .buffer_effective = undefined,
231:         };
232:     }
233: 
234:     fn add(self: *State, c: u8) void {
235:         // Only allow a-zA-Z.
236:         assert(std.ascii.isAlphabetic(c));
237: 
238:         // The buffer_modification index must be inbound of the buffer_effective.
239:         assert(self.buffer_modification_index == null or self.buffer_modification_index.? < self.buffer_effective.len);
240: 
241:         // Input mode must be either .literal or .telex.
242:         assert(self.mode == .literal or self.mode == .telex);
243: 
244:         // Should never set literal_index in .literal mode.
245:         if (self.mode == .literal) {
246:             assert(self.literal_index == null);
247:         }
248: 
249:         if (self.literal_index) |literal_index| {
250:             // When literal_index is set, mode must be .telex.
251:             assert(self.mode == .telex);
252:             // The literal_index value must be in range null or 0 -> 16 (buffer_effective length)
253:             // because we won't process Vietnamese input outside the buffer_effective.
254:             assert(literal_index <= self.buffer_effective.len);
255:             // The literal_index value must be less than buffer length.
256:             assert(literal_index < self.buffer_length);
257:         }
258: 
259:         switch (c) {
260:             'A', 'a' => {
261:                 if (self.literal_index != null or self.mode == .literal or self.buffer_length == 0) {
262:                     // 1. Enable literal input when literal_index is set or on literal mode. The
263:                     // literal_index is also set when the word starts with non-Vietnamese onsets.
264:                     // 2. Append literal because no previous span existed. Continue Vietnamese
265:                     // processing on next input.
266:                     self.append_literal(c);
267:                     // Set modification index to null because we didn't modify any existing span.
268:                     self.buffer_modification_index = null;
269:                 } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .empty)) {
270:                     // 3. Previous span is 'A' or 'a', apply circumflex.
271:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
272:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
273:                     // Set modification index for calculating synthetic backspace.
274:                     self.buffer_modification_index = self.buffer_length - 1;
275:                 } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .breve)) {
276:                     // 4. Previous span is 'Ă' or 'ă', override to circumflex.
277:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
278:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
279:                     // Set modification index for calculating synthetic backspace.
280:                     self.buffer_modification_index = self.buffer_length - 1;
281:                 } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .circumflex)) {
282:                     // 5. Previous span is 'Â' or 'â', cancel circumflex for previous span and append new literal span.
283:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
284:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
285:                     // Set modification index for calculating synthetic backspace.
286:                     self.buffer_modification_index = self.buffer_length - 1;
287:                     // Start literal input from this position.
288:                     self.literal_index = self.buffer_length;
289:                     // Append literal 'A' or 'a'.
290:                     self.append_literal(c);
291:                 } else if (!self.buffer_effective_last().equals_base(c)) {
292:                     // 6. Append literal when previous span is not 'A', 'a' and its variants.
293:                     if (self.buffer_length == self.buffer_effective.len) {
294:                         // Start literal input from this position when buffer_length exceeds the buffer_effective.
295:                         self.literal_index = self.buffer_length;
296:                     }
297:                     self.append_literal(c);
298:                     // No modification.
299:                     self.buffer_modification_index = null;
300:                 } else {
301:                     unreachable;
302:                 }
303:             },
304:             'C', 'c' => {}, // fill missing diacritic, e.g. cước.
305:             'D', 'd' => { // stroke.
306:                 if (self.literal_index != null or self.mode == .literal or self.buffer_length == 0) {
307:                     // 1. Enable literal input when literal_index is set or on literal mode. The
308:                     // literal_index is also set when the word starts with non-Vietnamese onsets.
309:                     // 2. Append literal because no previous span existed. Continue Vietnamese
310:                     // processing on next input.
311:                     self.append_literal(c);
312:                     // Set modification index to null because we didn't modify any existing span.
313:                     self.buffer_modification_index = null;
314:                 } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .empty)) {
315:                     // 3. Previous span is 'D' or 'd', apply stroke.
316:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
317:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .stroke, span_previous.tone);
318:                     // Set modification index for calculating synthetic backspace.
319:                     self.buffer_modification_index = self.buffer_length - 1;
320:                 } else if (self.buffer_effective_last().equals_ignore_case_and_tone(c, .stroke)) {
321:                     // 4. Previous span is 'Đ' or 'đ', cancel stroke for previous span and append new literal span.
322:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
323:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .empty, span_previous.tone);
324:                     // Set modification index for calculating synthetic backspace.
325:                     self.buffer_modification_index = self.buffer_length - 1;
326:                     // Start literal input from this position.
327:                     self.literal_index = self.buffer_length;
328:                     // Append literal 'D' or 'd'.
329:                     self.append_literal(c);
